class ConfigParserWithComments:
    def __init__(self):
        self.sections = {}
        self.comments = {}
    def add_section(self, section, comment=None):
        self.sections[section] = {}
        if comment:
            self.comments[section] = comment
    def set(self, section, option, value):
        self.sections[section][option] = value
    def write(self, file):
        for section in self.sections:
            if section in self.comments:
                file.write(self.comments[section] + '\n')
            file.write('[' + section + ']\n')
            for option, value in self.sections[section].items():
                if '\n' in value:
                    lines = value.split('\n')
                    file.write(option + ' = ' + lines[0] + '\n')
                    for line in lines[1:]:
                        file.write(' ' + line + '\n')
                else:
                    file.write(option + ' = ' + value + '\n')
            file.write('\n')

config = ConfigParserWithComments()
config.add_section('General', '; General section')
config.set('General', 'version', '1.0')
config.set('General', 'enabled', 'yes')
config.set('General', 'description', 'line1\nline2')
config.add_section('User', '; User section')
config.set('User', 'name', 'Alice')
